(function() {
  'use strict';

  console.log("LOG: Plugin Shortcode (min) carregado!");

  tinymce.PluginManager.add('shortcode', function(editor) {

    // Utilitários para codificação (Base64) para proteger o código dentro do placeholder
    function encodeContent(str) {
        if (!str) return "";
        try {
            return btoa(unescape(encodeURIComponent(str)));
        } catch(e) { return ""; }
    }

    function decodeContent(str) {
        if (!str) return "";
        try {
            return decodeURIComponent(escape(atob(str)));
        } catch(e) { return ""; }
    }

    /**
     * 1. DB -> EDITOR (Entrada)
     * Transforma [tag attrs]conteúdo[/tag] ou [tag attrs] em Placeholder Visual
     */
    editor.on('BeforeSetContent', function(e) {
      if (!e.content) return;

      // Regex para capturar shortcodes [script], [style] ou [link]
      const pattern = /\[(script|style|link)((?:\s+[a-zA-Z0-9_\-]+=(?:"[^"]*"|'[^']*'))*)\s*\](?:([\s\S]*?)\[\/\1\])?/gi;

      e.content = e.content.replace(pattern, function(match, tag, attrs, content) {
        const type = tag.toLowerCase();
        const encodedBody = encodeContent(content || "");
        const label = 'Shortcode: ' + type.toUpperCase();

        // Cores baseadas no tipo
        const colors = {
            script: { bg: '#fff7ed', border: '#f97316', text: '#9a3412' },
            style:  { bg: '#f0f9ff', border: '#0ea5e9', text: '#075985' },
            link:   { bg: '#f0fdf4', border: '#22c55e', text: '#166534' }
        };
        const theme = colors[type] || colors.script;

        return `<span class="tmce-shortcode-placeholder"
                     data-tag="${type}"
                     data-attrs="${tinymce.util.Tools.htmlEncode(attrs || "")}"
                     data-content="${encodedBody}"
                     contenteditable="false"
                     style="display:inline-block; background:${theme.bg}; border:1px dashed ${theme.border}; padding:4px 10px; cursor:pointer; font-family:monospace; font-size:12px; color:${theme.text}; margin:2px 0; border-radius:4px; font-weight:bold;">
                    [${label}]
                </span>`;
      });
    });

    /**
     * 2. EDITOR -> DB (Saída)
     * Transforma Placeholder Visual de volta em [tag attrs]conteúdo[/tag]
     */
    editor.on('GetContent', function(e) {
      if (e.format !== 'raw' && e.content) {
          const doc = new DOMParser().parseFromString(e.content, 'text/html');
          const placeholders = doc.querySelectorAll('.tmce-shortcode-placeholder');

          placeholders.forEach(el => {
              const tag = el.getAttribute('data-tag');
              const attrs = el.getAttribute('data-attrs');
              const content = decodeContent(el.getAttribute('data-content'));

              let shortcode = `[${tag}${attrs}]`;
              if (tag !== 'link' || content) {
                  shortcode += `${content}[/${tag}]`;
              }

              el.outerHTML = shortcode;
          });
          e.content = doc.body.innerHTML;
      }
    });

    // Função auxiliar para abrir o diálogo de edição/inserção
    function openShortcodeDialog(existingNode = null) {
        const isEdit = !!existingNode;
        const data = isEdit ? {
            type: existingNode.getAttribute('data-tag'),
            attrs: existingNode.getAttribute('data-attrs').trim(),
            content: decodeContent(existingNode.getAttribute('data-content'))
        } : {
            type: 'script',
            attrs: '',
            content: ''
        };

        editor.windowManager.open({
            title: (isEdit ? 'Editar ' : 'Inserir ') + 'Shortcode Técnico',
            body: {
                type: 'panel',
                items: [
                    {
                        type: 'selectbox',
                        name: 'type',
                        label: 'Tipo (Tag)',
                        items: [
                            {text: 'Script [script]', value: 'script'},
                            {text: 'Estilo [style]', value: 'style'},
                            {text: 'Link [link]', value: 'link'}
                        ]
                    },
                    { type: 'input', name: 'attrs', label: 'Atributos (ex: src="...", rel="...")' },
                    { type: 'textarea', name: 'content', label: 'Conteúdo Interno (Código/CSS)', minHeight: 200 }
                ]
            },
            initialData: data,
            buttons: [
                { type: 'cancel', text: 'Cancelar' },
                { type: 'submit', text: isEdit ? 'Atualizar' : 'Inserir', primary: true }
            ],
            onSubmit: function(api) {
                const newData = api.getData();
                const encoded = encodeContent(newData.content);
                const label = 'Shortcode: ' + newData.type.toUpperCase();

                // Re-renderiza o HTML do placeholder com o novo conteúdo
                // (O estilo inline aqui deve ser igual ao do BeforeSetContent)
                const colors = { script: '#f97316', style: '#0ea5e9', link: '#22c55e' };
                const bgColors = { script: '#fff7ed', style: '#f0f9ff', link: '#f0fdf4' };

                const html = `<span class="tmce-shortcode-placeholder"
                                   data-tag="${newData.type}"
                                   data-attrs=" ${tinymce.util.Tools.htmlEncode(newData.attrs.trim())}"
                                   data-content="${encoded}"
                                   contenteditable="false"
                                   style="display:inline-block; background:${bgColors[newData.type]}; border:1px dashed ${colors[newData.type]}; padding:4px 10px; cursor:pointer; font-family:monospace; font-size:12px; color:#333; margin:2px 0; border-radius:4px; font-weight:bold;">
                                  [${label}]
                              </span>`;

                if (isEdit) {
                    existingNode.outerHTML = html;
                } else {
                    editor.insertContent(html + ' ');
                }
                api.close();
            }
        });
    }

    /**
     * 3. CLIQUE PARA EDITAR
     */
    editor.on('Click', function(e) {
      const node = editor.dom.getParent(e.target, 'span.tmce-shortcode-placeholder');
      if (node) {
        e.preventDefault();
        openShortcodeDialog(node);
      }
    });

    /**
     * 4. BOTÃO NA TOOLBAR
     */
    editor.ui.registry.addButton('customscriptstyle', {
      icon: 'code-sample',
      tooltip: 'Inserir Script/Style/Link (Shortcode)',
      onAction: function() {
        openShortcodeDialog();
      }
    });

    return {
        getMetadata: function () {
            return { name: "Lunar Shortcodes Plugin" };
        }
    };
  });
})();
